  ('IND_DAI_D07', 'Synthetic, Semantic & Data Enrichment Operations', 'Owns synthetic data generation, labeling/annotation operations, human-in-the-loop evaluation, dataset enrichment, knowledge graph/semantic relationship modeling, and semantic AI data structures.', now(), now()),
  ('IND_AGR_D01', 'Field Crop Production Operations', 'Covers the planning, cultivation, monitoring, harvesting, and basic farm-level management of field crops such as cereals, pulses, oilseeds, cotton, sugarcane, and other broad-acre crops. This domain includes land preparation, sowing, irrigation, nutrient application, pest and disease monitoring, harvest readiness, and yield-related field operations.', now(), now()),
  ('IND_AGR_D02', 'Horticulture, Plantation and Protected Production', 'Covers production of fruits, vegetables, flowers, spices, plantation crops, nursery crops, and crops grown under protected conditions such as greenhouses, polyhouses, shade nets, and controlled cultivation systems. This domain includes crop establishment, canopy care, irrigation, pruning, fertigation, pest management, harvesting, grading, and quality-focused production practices.', now(), now()),
  ('IND_AGR_D03', 'Livestock, Dairy and Poultry Production', 'Covers animal-based production systems including cattle, buffalo, goats, sheep, pigs, poultry, and dairy operations. This domain includes animal feeding, housing, breeding support, health monitoring, milk production, egg/meat production, hygiene practices, farm biosecurity, productivity tracking, and routine farm operations.', now(), now()),
  ('IND_AGR_D04', 'Fisheries and Aquaculture Operations', 'Covers capture fisheries, inland fisheries, marine fisheries, aquaculture, hatchery operations, pond/tank/cage culture, fish/shrimp farming, and related production activities. This domain includes water-quality monitoring, feeding, stocking, disease observation, harvesting, handling, and basic compliance with sustainable and safe fishery practices.', now(), now()),
  ('IND_AGR_D05', 'Forestry, Agroforestry, Bamboo and Forest Produce Operations', 'Covers forest management, agroforestry systems, bamboo cultivation, nursery operations, forest produce collection, plantation maintenance, and community-linked forest resource activities. This domain includes tree planting, silviculture support, forest produce handling, bamboo processing support, conservation-linked operations, and sustainable use of forest resources.', now(), now()),
  ('IND_AGR_D06', 'Agricultural Inputs, Mechanization and Advisory Services', 'Covers the supply, usage support, and field advisory around seeds, fertilizers, crop protection products, animal inputs, farm machinery, irrigation systems, digital tools, and extension services. This domain includes input selection, equipment operation support, farmer advisory, demonstration activities, service delivery, troubleshooting, and responsible input-use guidance.', now(), now()),
  ('IND_AGR_D07', 'Produce Aggregation, Post-Harvest Handling and Market Linkage', 'Covers activities after production, including collection, sorting, grading, cleaning, packing, storage, primary processing, transport coordination, buyer linkage, mandi/FPO/market interaction, and farm-to-market logistics. This domain ensures agricultural, livestock, fishery, and forest produce move from producers to buyers with reduced loss, better quality control, and improved market access.', now(), now()),
  ('IND_BCP_D01', 'Customer Banking, Relationship and Service Operations', 'Customer-facing and service-facing banking work across retail, branch, digital, phone banking and business banking support, including account/service interaction and regulated customer communication.', now(), now()),
  ('IND_BCP_D02', 'Credit, Lending Support and Portfolio Monitoring', 'Credit-support and lending operations work that collects borrower evidence, supports underwriting documentation, monitors repayment/portfolio indicators and preserves conduct boundaries.', now(), now()),
  ('IND_BCP_D03', 'Payment Rail, Product and Merchant Acceptance Operations', 'Operational work around payment rails, payment products, acceptance enablement, bank/partner coordination and merchant activation across NPCI and payment-aggregator ecosystems.', now(), now()),
  ('IND_BCP_D04', 'Payment Settlement, Reconciliation, Dispute and Fraud Controls', 'Payment exception work involving settlement support, transaction reconciliation, failed transactions, chargebacks, dispute case evidence and fraud/risk signals.', now(), now()),
  ('IND_BCP_D05', 'Securities Intermediary, Exchange and Investor Operations', 'Front/middle/back-office support for securities market intermediaries and exchange-linked operations, including client records, trade lifecycle support, listing/member/market-data operations and investor grievance handling.', now(), now()),
  ('IND_BCP_D06', 'Clearing, Settlement, Depository, Custody and RTA Operations', 'Post-trade and recordkeeping operations across clearing corporations, settlement obligations, depositories, DPs, custody interfaces, RTA records, corporate actions and investor-service timelines.', now(), now()),
  ('IND_BCP_D07', 'Regulatory Control Support, Financial Crime Screening and Operational Reporting Preparation', 'Cross-sector support work with clear regulatory boundaries: KYC/CDD, AML/sanctions screening, suspicious transaction escalation support, operational-risk evidence, audit trails and regulated reporting preparation.', now(), now()),
  ('IND_CIE_D01', 'Built Environment Construction Delivery', 'Building structural/civil works, MEP coordination, fit-out/interior delivery, project handover and defects closure.', now(), now()),
  ('IND_CIE_D02', 'Transportation Corridor and Civil Structures Delivery', 'Roads, highways, bridges, tunnels, rail, metro, corridors, depots and transport structures from planning package through site execution/supervision.', now(), now()),
  ('IND_CIE_D03', 'Urban Water and Environmental Utility Delivery', 'Water supply, sewerage, septage, WTP/STP/FSTP, drainage and utility-network project delivery.', now(), now()),
  ('IND_CIE_D04', 'Energy and Power Infrastructure Delivery', 'Transmission lines, substations, distribution network works, renewables balance-of-plant and project commissioning interfaces.', now(), now()),
  ('IND_CIE_D05', 'Industrial, Process Plant and Heavy Engineering EPC Delivery', 'Process plants, refineries, chemical plants, industrial utilities, advanced facilities/data centers and heavy industrial EPC interfaces.', now(), now()),
  ('IND_CIE_D06', 'Specialized Marine, Port, Airport and Aviation Infrastructure Delivery', 'Ports, berths, jetties, marine/coastal structures, airports, terminals, runways, taxiways, aprons and airside/landside infrastructure.', now(), now()),
  ('IND_CIE_D07', 'Engineering Design, Project Controls and Delivery Assurance Support', 'Design engineering, BIM/VDC, PMC, project controls, QS/cost, quality, safety, contracts/procurement and delivery assurance where these support asset-class projects.', now(), now()),
  ('IND_EDS_D01', 'Formal Education & Lifelong Learning Delivery', 'Owns structured delivery environments spanning early childhood, K-12, higher education and adult/lifelong learning where learners progress through age, academic, institutional or continuing-education pathways.', now(), now()),
