  ('IND_EDS_D05', 'Assessment, Certification & Credentialing', 'Owns evidence signals for exams, evaluation, psychometrics, certification pathways, credentialing, score/reporting and language or professional assessment governance.', now(), now()),
  ('IND_EDS_D06', 'Learner Support, Guidance & Coaching Services', 'Owns learner-facing support signals including inclusive learning, special education, language development, academic mentoring, career discovery, counseling, learner progression support, and coached skill development such as sports, arts and performing skills where the operating pattern is learner-facing coaching.', now(), now()),
  ('IND_EDS_D07', 'Education Governance, Infrastructure & Knowledge Services', 'Owns administrative, policy, public-program, infrastructure, education data, admissions, research and academic publishing signals that enable or govern education operations.', now(), now()),
  ('IND_HWS_D01', 'Talent Acquisition & Recruitment Services', 'Owns employer hiring demand intake, candidate sourcing, structured screening, interview coordination, candidate evaluation alignment, and hiring pipeline movement for permanent and role-based hiring services.', now(), now()),
  ('IND_HWS_D02', 'Staffing, EOR & External Workforce Deployment', 'Owns workforce supply deployment beyond direct permanent hiring, including temporary staffing, specialist secondment, managed HR service delivery, employer-of-record administration, global hiring setup, and local employment compliance coordination for external or distributed workforces.', now(), now()),
  ('IND_HWS_D03', 'Payroll, Rewards, Benefits & Statutory Compliance Operations', 'Owns pay, benefits, reward, wage, deduction, contribution, tax withholding, salary benchmarking, and statutory compliance operations where HR service providers administer or advise employer workforce obligations.', now(), now()),
  ('IND_HWS_D04', 'HR Operations, People Systems & Service Delivery', 'Owns employee lifecycle administration, HR service intake, HR case/knowledge routing, core HR data management, HRIS/HCM reporting, ATS integration support, and employee request fulfillment as an operational service layer.', now(), now()),
  ('IND_HWS_D05', 'Workforce Strategy, HR Advisory & Planning', 'Owns HRBP advisory, HR operating-model coordination, workforce demand/supply analysis, workforce gap analysis, action planning, skills planning, and people-strategy alignment with business objectives.', now(), now()),
  ('IND_HWS_D06', 'Learning, Performance, Engagement & Workforce Development', 'Owns workforce capability development signals including training needs assessment, instructional design, performance expectation definition, feedback/review support, development follow-up, engagement interpretation, manager action planning, and employee-experience improvement loops.', now(), now()),
  ('IND_HWS_D07', 'Employee Relations, Workplace Risk & Transition Support', 'Owns employee relations support, grievance and disciplinary procedure signals, workplace conflict/dispute handling, investigation coordination, background-screening risk controls, termination administration, offboarding, layoff transition, career coaching, and outplacement support.', now(), now()),
  ('IND_MEG_D01', 'Content Creation, Editorial & Creative Production', 'Owns creative content shaping before or during production: editorial planning, promo ideation, creator/content policy readiness, script/promo adaptation, show breakdown, podcast/show setup, and creative coordination where the business objective is audience-facing content output.', now(), now()),
  ('IND_MEG_D02', 'Post-production, VFX, Animation & Finishing', 'Owns technical and craft finishing of media assets: VFX editorial intake, shot turnover checks, editing collaboration, color management, audio loudness compliance, character animation, rendering, and delivery-facing technical QC.', now(), now()),
  ('IND_MEG_D03', 'Streaming, Broadcast & Platform Delivery Operations', 'Owns delivery, encoding, packaging, standards compliance, and platform/broadcast readiness for video/audio/timed-text assets once content is prepared for distribution.', now(), now()),
  ('IND_MEG_D04', 'Game Development, QA & Release Operations', 'Owns game build creation, test validation, platform compliance, release packaging, storefront readiness, app review prevention, and mobile/OTT quality engineering where the product is interactive/game or app-like software.', now(), now()),
  ('IND_MEG_D05', 'Advertising, Creator Monetization & Rights Operations', 'Owns monetization, campaign execution support, rights/copyright response, ad asset readiness, ad serving standards, sales operations, and revenue-supporting operational controls.', now(), now()),
  ('IND_MEG_D06', 'Music, Audio, Podcast & Live Experience Operations', 'Owns release and experience operations for non-video-platform media channels and live/experiential activity: event setup, ticketing, inventory, attendee data, ingress monitoring, playlist pitching, and podcast/music distribution workflows.', now(), now()),
  ('IND_PBM_D01', 'Small-Molecule Pharma Manufacturing and Regulatory Evidence', 'Covers API/intermediate and finished-dose pharma work objects where evidence centers on drug substance/product, formulation dossier, batch record, stability, packaging, CMC, export/domestic authorization support, and GMP quality evidence.', now(), now()),
  ('IND_PBM_D02', 'Biological Products, Vaccines and Biosimilar Operations', 'Covers mature biological product, vaccine, and biosimilar industry structure where evidence centers on biological product controls, vaccine supply, biologics QA/regulatory evidence, cold-chain/comparability signals, and biological-product manufacturing context.', now(), now()),
  ('IND_PBM_D03', 'Clinical Development and Safety Evidence Services', 'Covers CRO, clinical operations, clinical trial regulatory support, pharmacovigilance, medical safety, medical writing, and clinical data services where evidence artifacts are study, safety, and clinical documentation records rather than manufacturing batches.', now(), now()),
  ('IND_PBM_D04', 'Bioinformatics, Genomics and Bioservices Delivery', 'Covers computational biology, genomics, bioinformatics, assay services, research-tool and bioservices outputs where work objects are sample metadata, assay outputs, sequencing/omics datasets, pipelines, and client scientific reports.', now(), now()),
  ('IND_PBM_D05', 'Industrial Biotechnology and Biomanufacturing', 'Covers BioIndustrial, biofoundry, precision fermentation, enzymes, bio-based materials/chemicals, pilot/pre-commercial scale-up, DBTL cycle evidence, and industrial bioprocess records.', now(), now()),
  ('IND_PBM_D06', 'Agri-Biotechnology and Seed/Biological Applications', 'Covers BioAgri, seed biotechnology, crop/agri biologicals, genomics, transgenics/gene editing, germplasm evidence, field evidence, and agri-biotech license-to-operate/policy-regulatory support.', now(), now()),
  ('IND_PBM_D07', 'MedTech Device, Diagnostic and Software-Regulated Product Evidence', 'Covers regulated medical devices/equipment, IVD diagnostic platforms, and software-regulated medical-device products where evidence centers on MDR classification, technical documentation, DHF/DMR, risk files, test reports, PMS, IVD performance, and SaMD lifecycle records.', now(), now()),
