  ('IND_RCE_D01', 'Store Retail & Omnichannel Operations', 'Owns physical store execution, floor leadership, POS-enabled customer transactions, local inventory routines, customer issue handling, and pickup handoff coordination where the store is the operating moment.', now(), now()),
  ('IND_RCE_D02', 'E-commerce, Marketplace & Digital Commerce Operations', 'Owns online order operations, seller/marketplace execution, product feed and listing operations, digital fulfillment coordination, marketplace inventory visibility, and digital conversion operations.', now(), now()),
  ('IND_RCE_D03', 'Category, Merchandising, Pricing & Commercial Growth', 'Owns commercial category direction, assortment, vendor/commercial inputs, pricing and promotion governance, planogram/space planning, shelf presentation logic, and retail growth levers.', now(), now()),
  ('IND_RCE_D04', 'CPG Sales, Trade & Channel Execution', 'Owns manufacturer/brand-side market execution across distributors, territories, outlets, trade activations, retail visibility, secondary sales, and channel performance signals.', now(), now()),
  ('IND_RCE_D05', 'Supply Chain, Inventory & Fulfillment Control', 'Owns stock, product-data, replenishment, warehouse/inventory-control, and delivery-exception coordination at a structural level only. D05 must not become a catch-all: product master data, inventory control, replenishment planning, and last-mile exceptions should be separated later only at workflow/capability level when evidence supports it.', now(), now()),
  ('IND_RCE_D06', 'Customer Experience, Support & Loyalty', 'Owns customer issue handling, returns/exchange experience, support-ticket intake and escalation, loyalty/member engagement, reward redemption, and customer recovery moments.', now(), now()),
  ('IND_RCE_D07', 'Risk, Quality, Compliance & Sustainability', 'Owns exception/control work across product quality, recalls, regulatory documentation, loss prevention, payment disputes/fraud response, and sustainability/packaging compliance at a structural level only. D07 must remain bounded: risk, quality, compliance, payment disputes, loss prevention, recalls, sustainability, and packaging should not be merged into one capability later.', now(), now()),
  ('IND_TLC_D01', 'Mobile Access Network Field and RAN Operations', 'Manage field-level mobile access network activities including cell-site checks, RAN equipment readiness, antenna/radio issue reporting, outage evidence collection, site visit coordination and handoff to network operations teams.', now(), now()),
  ('IND_TLC_D02', 'Mobile Core, Subscriber Traffic, and Service Assurance', 'Monitor mobile core service behaviour, subscriber traffic patterns, service-impact alarms, incident tickets and restoration evidence to support mobile voice, data and subscriber-service continuity.', now(), now()),
  ('IND_TLC_D03', 'FTTH and Fiber Access Deployment', 'Coordinate fiber-to-the-home deployment activities including route readiness, fiber laying, splicing, ONT installation support, customer premises readiness, test records and activation handoff.', now(), now()),
  ('IND_TLC_D04', 'Fixed Wireless and Home CPE Enablement', 'Support fixed wireless and home CPE setup by checking device readiness, SIM/router configuration, signal quality, installation evidence, customer activation status and service handoff records.', now(), now()),
  ('IND_TLC_D05', 'Broadband Access Service Assurance', 'Track broadband service quality by reviewing customer complaints, access-network alarms, modem/ONT status, speed or connectivity evidence, technician updates and restoration closure notes.', now(), now()),
  ('IND_TLC_D06', 'Tower Site Operations and Energy/Uptime Management', 'Coordinate tower-site uptime by monitoring power availability, DG/battery status, site access, preventive maintenance, energy alarms, downtime evidence and field-vendor recovery actions.', now(), now()),
  ('IND_TLC_D07', 'RoW, Duct, Pole, and Dark-Fiber Infrastructure Permissions', 'Manage infrastructure-permission support for telecom routes by tracking right-of-way applications, duct or pole usage records, dark-fiber documentation, municipal/vendor dependencies and approval handoff evidence.', now(), now()),
  ('IND_TLC_D08', 'ISP Routing, IP Transit, and Peering Operations', 'Support internet service provider network operations by tracking routing updates, peering sessions, IP transit links, BGP or latency issues, traffic shifts and escalation records for internet connectivity stability.', now(), now()),
  ('IND_TLC_D09', 'Broadband Aggregation and Subscriber Internet Operations', 'Monitor broadband aggregation systems, subscriber sessions, access gateways, authentication failures, traffic congestion, service alarms and issue handoffs affecting mass-market internet users.', now(), now()),
  ('IND_TLC_D10', 'Enterprise SD-WAN and Managed WAN Service Delivery', 'Coordinate enterprise SD-WAN and managed WAN service delivery by tracking site readiness, circuit status, device configuration, customer acceptance, SLA milestones and managed-service incident records.', now(), now()),
  ('IND_TLC_D11', 'Cloud Connect, Private Line, and Enterprise Internet Services', 'Support enterprise connectivity services by managing cloud-connect requests, private line readiness, enterprise internet circuits, bandwidth records, service testing evidence and customer handoff documentation.', now(), now()),
  ('IND_TLC_D12', 'Optical Transport, OTN/DWDM, and Backbone Operations', 'Monitor optical backbone operations including OTN/DWDM links, fiber routes, capacity cards, alarms, protection switching, link degradation evidence and backbone restoration handoffs.', now(), now()),
  ('IND_TLC_D13', 'NLD/ILD Capacity, Interconnect, and Leased Bandwidth Coordination', 'Coordinate national and international long-distance capacity by tracking interconnect requests, leased bandwidth records, capacity allocation, circuit provisioning milestones and carrier/customer coordination evidence.', now(), now()),
  ('IND_TLC_D14', 'Satellite Authorization, Frequency Assignment, and VSAT Network Records', 'Support satellite service compliance records by tracking authorization documents, frequency assignments, VSAT network details, terminal records, regulatory references and service activation documentation.', now(), now()),
  ('IND_TLC_D15', 'VSAT Hub, Terminal, and Satellite Managed Service Operations', 'Manage VSAT service operations by monitoring hub status, terminal availability, link performance, installation records, remote-site tickets, outage evidence and managed-service restoration actions.', now(), now()),
  ('IND_TLC_D16', 'PM-WANI Public Wi-Fi Hotspot Onboarding and Operations', 'Support public Wi-Fi hotspot operations by coordinating PM-WANI onboarding records, PDO/PDOA details, hotspot activation, usage status, fault reports and service-continuity evidence.', now(), now()),
  ('IND_TLC_D17', 'Private / Professional Mobile Radio and Trunked Critical Communications', 'Coordinate private and professional mobile radio operations by tracking radio users, talk groups, trunked network status, coverage complaints, emergency-service continuity records and critical-communication incident handoffs.', now(), now()),
  ('IND_TLC_D18', 'Submarine Cable Landing Station and International Gateway Operations', 'Support submarine cable and international gateway operations by tracking landing-station records, cable system status, international capacity, gateway alarms, maintenance windows and restoration coordination evidence.', now(), now()),
  ('IND_GPS_D01', 'Citizen Service Platform Operations', 'Manages digital and assisted-service platforms used by citizens to access government services, submit applications, track requests, raise grievances, and receive status updates. This domain covers service workflows, citizen support, ticket handling, SLA monitoring, document intake, escalation, and coordination with departments to ensure timely and reliable public service delivery.', now(), now()),
  ('IND_GPS_D02', 'GovTech Product, Security and Data Support', 'Supports government technology products, digital platforms, data systems, cybersecurity controls, user access, and platform reliability. This domain works across product teams, IT operations, security teams, and data owners to maintain secure, compliant, and usable digital public infrastructure.', now(), now()),
  ('IND_GPS_D03', 'Municipal Civic Administration and Ward Service Governance', 'Coordinates municipal services at city, zone, and ward levels, including citizen requests, local inspections, permits, grievance resolution, service records, and inter-department follow-up. This domain ensures that civic services are tracked, governed, and delivered according to municipal rules and public accountability standards.', now(), now()),
  ('IND_GPS_D04', 'Municipal Technical Works and Engineering Support', 'Supports planning, execution, inspection, and documentation of municipal engineering works such as roads, footpaths, drains, streetlights, buildings, and public infrastructure repairs. This domain focuses on technical estimates, site evidence, contractor coordination, quality checks, work progress tracking, and handover documentation.', now(), now()),
  ('IND_GPS_D05', 'Smart City ICCC Operations and Urban Data Monitoring', 'Operates Integrated Command and Control Centre systems used to monitor city services, traffic, safety alerts, utilities, environment, incidents, and urban data dashboards. This domain supports real-time monitoring, alert triage, incident logging, escalation, and evidence-based coordination with field and control-room teams.', now(), now()),
  ('IND_GPS_D06', 'Smart City Project, Vendor and PMC Coordination', 'Coordinates smart city projects involving government departments, vendors, system integrators, consultants, and project management consultants. This domain tracks project milestones, deliverables, risks, approvals, site readiness, documentation, billing support, and implementation governance.', now(), now()),
  ('IND_GPS_D07', 'Metro Operations and Maintenance', 'Supports daily operation and maintenance of metro rail systems, including station operations, passenger flow, train service coordination, safety procedures, asset checks, maintenance logs, incident response, and service continuity. This domain focuses on safe, punctual, and reliable urban rail movement.', now(), now()),
  ('IND_GPS_D08', 'Bus, Depot and E-Bus Operations', 'Manages public bus operations, depot activities, driver and conductor coordination, fleet readiness, route scheduling, charging infrastructure for e-buses, service disruptions, vehicle dispatch, maintenance coordination, and passenger service quality. This domain ensures reliable and efficient bus-based public transport delivery.', now(), now()),
  ('IND_GPS_D09', 'Fare, AFC, NCMC and ITMS Systems', 'Supports fare collection and transport technology systems, including Automated Fare Collection, National Common Mobility Card integration, ticketing devices, validators, passenger information systems, fleet tracking, and Intelligent Transport Management Systems. This domain monitors system uptime, transaction accuracy, device readiness, and issue escalation.', now(), now()),
  ('IND_GPS_D10', 'Urban Water Supply and Distribution', 'Supports municipal water supply operations, including source-to-distribution coordination, pumping, storage, pipeline networks, pressure monitoring, meter data, leakage complaints, tanker support, quality alerts, and citizen service requests. This domain helps maintain safe, reliable, and accountable water delivery.', now(), now()),
  ('IND_GPS_D11', 'Urban Sewerage, Drainage and Septage Management', 'Manages sewer networks, stormwater drains, sewage pumping, treatment coordination, septic tank desludging, drainage complaints, overflow response, and monsoon preparedness. This domain supports sanitation reliability, public health protection, environmental compliance, and field-level service restoration.', now(), now()),
  ('IND_GPS_D12', 'Solid Waste Collection, Segregation and Field Supervision', 'Coordinates municipal solid waste collection, route supervision, source segregation, vehicle movement, transfer points, material recovery, field staff attendance, complaint handling, and service verification. This domain ensures visible cleanliness, operational discipline, and accountable waste management at ward and city levels.', now(), now()),
  ('IND_GPS_D13', 'Sanitation Certification, Compliance and Public Feedback', 'Supports sanitation audits, cleanliness certification, public feedback collection, compliance documentation, inspection evidence, corrective action tracking, and ranking-related readiness. This domain connects field sanitation performance with formal compliance, citizen perception, and improvement planning.', now(), now()),
  ('IND_GPS_D14', 'Disaster Preparedness, Planning and DMEx Coordination', 'Supports disaster preparedness through risk mapping, emergency planning, mock drills, department coordination, resource inventories, training exercises, and Disaster Management Exercise planning. This domain focuses on readiness before emergencies occur, ensuring that roles, resources, and response protocols are clear.', now(), now()),
  ('IND_GPS_D15', 'Disaster Response Coordination and Resource Governance', 'Coordinates emergency response during disasters or major incidents by tracking alerts, resources, shelters, relief materials, field teams, rescue support, inter-agency communication, and situation reports. This domain ensures that response actions are timely, documented, prioritized, and governed responsibly.', now(), now()),
  ('IND_GPS_D16', 'Public Procurement Compliance', 'Manages compliance across public procurement processes, including tender documentation, eligibility checks, bid evaluation support, approval routing, contract records, audit evidence, purchase rules, and vendor governance. This domain ensures transparency, fairness, traceability, and rule-based spending of public funds.', now(), now()),
  ('IND_GPS_D17', 'GeM Platform and Marketplace Operations', 'Supports government procurement through the Government e-Marketplace platform, including product/service search, bid creation, comparison, vendor communication, order processing, compliance checks, delivery tracking, invoice support, and record maintenance. This domain focuses on platform-based procurement accuracy and accountability.', now(), now()),
  ('IND_GPS_D18', 'Defense Operations and Armed Forces Administration', 'Supports administrative, logistics, personnel, asset, documentation, and operational coordination functions within defense and armed forces environments. This domain works within strict hierarchy, security, discipline, and confidentiality requirements to support mission readiness and institutional functioning.', now(), now()),
  ('IND_GPS_D19', 'Police, Courts and Justice Administration', 'Supports administrative and operational workflows across policing, legal case processing, court coordination, records management, summons, evidence documentation, citizen assistance, compliance tracking, and justice service delivery. This domain focuses on procedural accuracy, confidentiality, lawful handling, and timely coordination.', now(), now()),
  ('IND_GPS_D20', 'Public Healthcare Delivery', 'Supports government healthcare services across hospitals, clinics, public health programs, patient registration, appointment flow, records, medicine availability, referrals, diagnostics, outreach, emergency coordination, and scheme-linked service delivery. This domain focuses on accessible, safe, timely, and accountable healthcare for the public.', now(), now()),
  ('IND_GPS_D21', 'Public Education Delivery', 'Supports public education systems including school administration, teacher deployment, student records, learning support, infrastructure tracking, attendance, scheme implementation, assessment data, parent communication, and education department reporting. This domain ensures that public education services are organized, inclusive, and monitored.', now(), now()),
